#!/usr/bin/env python3
"""
Bug #0069: jax.jit produces wrong output vs jax.disable_jit.

Patterns    : [['fusion', 'matmul_bias_relu'], ['constant', 'relu_residual_sum'], ['normalization', 'reduce_l2_last'], ['layout', 'gather_slice_combo'], ['branch', 'add_layernorm'], ['fusion', 'gemm_alpha_beta_transb']]
Dependencies: numpy jax
Run         : python unique_0069.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([256, 64])
_w1 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w2 = np.frombuffer(bytes.fromhex("00000000"), dtype=np.float32).reshape([1])
_w3 = np.frombuffer(bytes.fromhex("00000000"), dtype=np.float32).reshape([1])
_w4 = np.frombuffer(bytes.fromhex("00000000"), dtype=np.float32).reshape([1])
_w5 = np.frombuffer(bytes.fromhex("00008042"), dtype=np.float32).reshape([1])
_w6 = np.frombuffer(bytes.fromhex("0000803f00008042"), dtype=np.float32).reshape([2])
_w7 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 64])
_w8 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w9 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w10 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64, 64])
_w11 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 256])  # input "model_input"


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_mmbrelu_mm = jnp.matmul(x, _w0)
    n0_mmbrelu_add = n0_mmbrelu_mm + _w1
    n0_mmbrelu_out = jnp.maximum(n0_mmbrelu_add, np.float32(0.0))
    n100_rrs_r = jnp.maximum(n0_mmbrelu_out, np.float32(0.0))
    n100_rrs_out = n100_rrs_r + n0_mmbrelu_out
    n200_redu_red = jnp.sqrt(jnp.sum(n100_rrs_out*n100_rrs_out, axis=(-1,), keepdims=True))
    n200_redu_z = n100_rrs_out * _w2
    n200_redu_out = n200_redu_z + n200_redu_red
    n300_gsc_g = jnp.take(n200_redu_out, _w3.astype(np.int32), axis=0)
    n300_gsc_sl = (lambda _x, _s, _e, _ax, _st: _x[tuple(slice(int(_s[k]),int(_e[k]) if abs(int(_e[k]))<2**30 else None,int(_st[k])) if k < len(_ax) else slice(None) for k in range(len(_x.shape)))])(n300_gsc_g, _w4, _w5, np.arange(len(n300_gsc_g.shape)), np.ones(len(_w4), dtype=np.int64))
    n300_gsc_out = jnp.broadcast_to(n300_gsc_sl, _w6.tolist())
    n400_aln_add = n300_gsc_out + _w7
    n400_aln_out = (((lambda _x: (lambda _m, _v: (_x - _m) / jnp.sqrt(_v + np.float32(9.999999747378752e-06)))(jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True), jnp.mean((_x - jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True))**2, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True)))(n400_aln_add)) * _w8) + _w9
    n500_gab_out = np.float32(0.8999999761581421) * jnp.matmul(n400_aln_out, jnp.swapaxes(_w10, -1, -2)) + np.float32(0.5) * _w11
    return jnp.asarray(n500_gab_out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)

    with jax.disable_jit():
        ref = np.array(model(x_jax), dtype=np.float32).ravel()

    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(ref.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(ref.astype(np.float64)) + 1e-8))
    print(f"expected (jax.disable_jit): {ref[:6]}")
    print(f"actual   (jax.jit)        : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
